sys_script_client.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
// RAJ 2020.02.18  STRY0060676 - Works with 2 UI Actions that Enable and Disable Shared Attachments for Stories STRY0060676 and STRY0060679
// if form action is either Enable Shared Attachments or Disable Shared Attachments, then prompt user before proceding.
function onSubmit() {

	var proceedWithSharedFolderChange = false;

	// RAJ STRY0060679
	// if form action is Disable Shared Attachments, then prompt user before proceding.
	if (g_form.getActionName() == 'tasker_disableSharedAttachments') {
		// TODO, NEED TO USE MSG RULES FOR MULTILANGUAGE
		proceedWithSharedFolderChange = confirm("Are you sure you want to disable shared attachments? There may be existing shared attachments in the task tree. Shared attachments will not be deleted but will be hidden");
		if (proceedWithSharedFolderChange == false) {
			// the user chose no and does not want to disable sharing of attachments for the entire tree
			// do not submit to server, cancel the submit
			return false;
		}
	}
	// RAJ - 2020-02-22 - STRY0060748
	// if form action is Disable Shared Documents, then prompt user before proceding.
	if (g_form.getActionName() == 'tasker_disableSharedDocuments') {
		// TODO, NEED TO USE MSG RULES FOR MULTILANGUAGE
		proceedWithSharedFolderChange = confirm("Are you sure you want to disable shared documents? There may be existing shared documents in the task tree. Shared documents will not be deleted but will be hidden.");
		if (proceedWithSharedFolderChange == false) {
			// the user chose no and does not want to disable sharing of attachments for the entire tree
			// do not submit to server, cancel the submit
			return false;
		}
	}
}
